const _QueenAttack = function QueenAttack(){
return class QueenAttack {
  constructor({
    black: [blackRow, blackColumn] = [0, 3],
    white: [whiteRow, whiteColumn] = [7, 3],
  } = {}) {
    if (whiteRow < 0 || whiteRow > 7 || whiteColumn < 0 || whiteColumn > 7) {
      throw new Error('Queen must be placed on the board');
    }
    if (blackRow < 0 || blackRow > 7 || blackColumn < 0 || blackColumn > 7) {
      throw new Error('Queen must be placed on the board');
    }
    if (whiteRow === blackRow && whiteColumn === blackColumn) {
      throw new Error('Queens cannot share the same space');
    }
    this.white = [whiteRow, whiteColumn];
    this.black = [blackRow, blackColumn];
  }

  toString() {
    const board = [];
    for (let row = 0; row < 8; row++) {
      const cols = [];
      for (let col = 0; col < 8; col++) {
        if (row === this.white[0] && col === this.white[1]) {
          cols.push('W');
        } else if (row === this.black[0] && col === this.black[1]) {
          cols.push('B');
        } else {
          cols.push('_');
        }
      }
      board.push(cols.join(' '));
    }
    return board.join('\n');
  }

  get canAttack() {
    const [wr, wc] = this.white;
    const [br, bc] = this.black;
    return wr === br || wc === bc || Math.abs(wr - br) === Math.abs(wc - bc);
  }
}
};

