const _Rational = function Rational(gcd){
  class Rational {
    constructor(numerator, denominator = 1) {
      if (denominator === 0 && numerator === 0) {
        throw new Error("Denominator and numerator cannot both be zero");
      }
      // Reduce to lowest terms with positive denominator
      const g = gcd(numerator, denominator);
      let n = numerator / g;
      let d = denominator / g;
      // Ensure denominator is positive
      if (d < 0) { n = -n; d = -d; }
      this.numerator = n;
      this.denominator = d;
    }

    add(other) {
      return new Rational(
        this.numerator * other.denominator + other.numerator * this.denominator,
        this.denominator * other.denominator
      );
    }

    sub(other) {
      return new Rational(
        this.numerator * other.denominator - other.numerator * this.denominator,
        this.denominator * other.denominator
      );
    }

    mul(other) {
      return new Rational(
        this.numerator * other.numerator,
        this.denominator * other.denominator
      );
    }

    div(other) {
      if (other.numerator === 0) throw new Error("Division by zero rational");
      return new Rational(
        this.numerator * other.denominator,
        this.denominator * other.numerator
      );
    }

    abs() {
      return new Rational(
        Math.abs(this.numerator),
        this.denominator
      );
    }

    exprational(power) {
      if (power === 0) return new Rational(1, 1);
      if (power > 0) {
        return new Rational(
          this.numerator ** power,
          this.denominator ** power
        );
      }
      // negative power: swap num/den, power becomes positive
      const m = Math.abs(power);
      return new Rational(
        this.denominator ** m,
        this.numerator ** m
      );
    }

    expreal(base) {
      // base^(a/b) = root(base^a, b) = (base^a)^(1/b)
      return (base ** this.numerator) ** (1 / this.denominator);
    }

    reduce() {
      // Already stored in reduced form
      return new Rational(this.numerator, this.denominator);
    }
  }
  return Rational;
};

