    constructor(inputCells, fn) {
      this._inputs = inputCells;
      this._fn = fn;
      this._callbacks = new Set();
      this._dependents = [];

      for (const input of inputCells) {
        input._dependents.push(this);
      }

      this.value = this._fn(inputCells.map(c => c.value));
    }

    addCallback(cb) {
      this._callbacks.add(cb);
    }

    removeCallback(cb) {
      this._callbacks.delete(cb);
    }
  }

