    // 1. Collect all transitive dependents via BFS
    const affected = new Set();
    const queue = [source];
    while (queue.length) {
      const cell = queue.shift();
      for (const dep of cell._dependents) {
        if (!affected.has(dep)) {
          affected.add(dep);
          queue.push(dep);
        }
