        if (affected.has(input)) {
          outgoing.get(input).push(cell);
          inDegree.set(cell, inDegree.get(cell) + 1);
        }
      }
    }

    const ready = [];
    for (const cell of affected) {
      if (inDegree.get(cell) === 0) ready.push(cell);
