  if (lines.length === 0) return 0;
  const rows = lines.length;
  const cols = lines[0].length;

  // Collect + positions grouped by row
  const rowPlus = {};
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      if (lines[r][c] === '+') {
        if (!rowPlus[r]) rowPlus[r] = [];
        rowPlus[r].push(c);
      }
    }
  }

  const rowKeys = Object.keys(rowPlus).map(Number).sort((a, b) => a - b);
  let rectangles = 0;

  // For each pair of rows with + corners
  for (let i = 0; i < rowKeys.length; i++) {
    for (let j = i + 1; j < rowKeys.length; j++) {
      const r1 = rowKeys[i];
      const r2 = rowKeys[j];

      // Find columns that have + at both r1 and r2
      const set1 = new Set(rowPlus[r1]);
      const commonCols = rowPlus[r2].filter(c => set1.has(c)).sort((a, b) => a - b);

      // For each pair of common columns (potential left & right edges)
